        allListings.push({
          title: titles[i],
          price: prices[i],
          location: locations[i],
          detailUrl: urls[i],
          scrapingTimestamp: timestamp,
          stableId: stableId
        });
      }

      console.log(`Found ${numListings} listings on page ${pageNum}`);

